#!/usr/bin/env python3
import json, sys

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    if ev.get("tool_name") != "Bash":
        return 0

    cmd = (ev.get("tool_input") or {}).get("command", "").strip()

    # Block "pnpm test" when it's not "pnpm test:ci"
    if cmd.startswith("pnpm test") and "test:ci" not in cmd:
        print("BLOCKING: use `pnpm test:ci` instead. `pnpm test` (when available) opens an interactive watcher and will not return.", file=sys.stderr)
        return 2

    return 0

if __name__ == "__main__":
    sys.exit(main())
